#include<bits/stdc++.h>
using namespace std;

/*
Construct a graph with N planets and K portals
A portal will connect two planets 
Weight of edge from planet i to portal j is C_i,j
Weight of edge from portal Ai to planet i is 0
Now run dijkstra for minimum distance
*/

const int N = 1e5 + 1;
const long long INF = 1e18;

long long d[N];
vector<pair<int,int>> adj[N];
bool vis[N];


void dijkstra(int source, int n) {
    for(int i = 1; i <= n; i++) {
        d[i] = INF, vis[i] = false;
    }
    d[source] = 0;
    priority_queue<pair<long long, int>> pq;
    pq.push({0, source});
    while(pq.size() != 0) {
        pair<long long, int> node = pq.top();
        pq.pop();
        int v = node.second;
        long long distance = node.first;
        if(vis[v]) {
            continue;
        }
        vis[v] = 1;
        for(auto edge: adj[v]) {
            int u = edge.first;
            int weight = edge.second;
            d[u] = min(d[u], d[v] + weight);
            pq.push({-d[u], u}); 
        }
    }      
}

int main() {
    int n, k; cin >> n >> k;
    int S; cin >> S;
    for(int i = 1; i <= n + k; i++) {
        adj[i].clear(); 
    }

    for(int i = 1; i <= n; i++) {
        int x; cin >> x;
        // xth portal has id -> x + n
        adj[x + n].push_back({i, 0});
    }

    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= k; j++) {
            int x; cin >> x;
            if(x == -1) { 
                // no edge
                continue; 
            }
            else {
                adj[i].push_back({j + n, x});
            }
        }
    }

    long long ans = INF;
    dijkstra(S, n + k);

    for(int i = 1; i <= n; i++) { 
        if(d[i] == INF) cout << -1 << " "; // Unreachable
         else cout << d[i] << " ";
    }
    return 0;
}

