import java.util.*;

/*
Construct a graph with N planets and K portals
A portal will connect two planets 
Weight of edge from planet i to portal j is C_i,j
Weight of edge from portal Ai to planet i is 0
Now run dijkstra for minimum distance
*/

class main {
    static final int N = 100001;
    static final long INF = (long)1e18;

    static long[] d = new long[N];
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    static class Pair {
        int node;
        long weight;

        Pair(int node, long weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    static void dijkstra(int source, int n) {
        for (int i = 1; i <= n; i++) {
            d[i] = INF;
            vis[i] = false;
        }
        d[source] = 0;
        PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> Long.compare(a.weight, b.weight));
        pq.add(new Pair(source, 0));

        while (!pq.isEmpty()) {
            Pair node = pq.poll();

            int v = node.node;
            long distance = node.weight;

            if (vis[v]) {
                continue;
            }
            vis[v] = true;

            for (Pair edge : adj[v]) {
                int u = edge.node;
                long weight = edge.weight;
                d[u] = Math.min(d[u], d[v] + weight);
                pq.add(new Pair(u, d[u]));
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int k = scanner.nextInt();
        int S = scanner.nextInt();

        for (int i = 1; i <= n + k; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 1; i <= n; i++) {
            int x = scanner.nextInt();
            // xth portal has id -> x + n
            adj[x + n].add(new Pair(i, 0));
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= k; j++) {
                int x = scanner.nextInt();
                if (x != -1) {
                    adj[i].add(new Pair(j + n, x));
                }
            }
        }

        dijkstra(S, n + k);

        for (int i = 1; i <= n; i++) {
            if (d[i] == INF) {
                System.out.print(-1 + " "); // Unreachable
            } else {
                System.out.print(d[i] + " ");
            }
        }
    }
}

